-- 1. DATABASE CREATION
DROP DATABASE IF EXISTS tprm_portfolio;
CREATE SCHEMA `tprm_portfolio`;
USE `tprm_portfolio`;


-- 2. CREATE VENDORS TABLE
CREATE TABLE tprm_vendors (
    Vendor_id INT PRIMARY KEY,
    Vendor_name VARCHAR(255),
    Category VARCHAR(100),
    Onboarding_date VARCHAR(50),
    Country VARCHAR(100),
    Contract_value DECIMAL(15, 2),
    Last_audit_score INT,
    Criticality VARCHAR(50),
    Data_access BOOLEAN,
    sla_uptime DECIMAL(10, 2),
    Incident_count INT,
    Risk_status VARCHAR(50)
);

-- 3. INSERTING VENDORS DATA


-- 4. CREATE AUDITS TABLE
CREATE TABLE vendor_audits (
    audit_id INT PRIMARY KEY,
    vendor_id INT, 
    audit_date VARCHAR(50),
    financial_score INT,
    cyber_score INT,
    compliance_score INT,
    overall_risk_rating VARCHAR(50),
    CONSTRAINT fk_vendor_link FOREIGN KEY(vendor_id) REFERENCES tprm_vendors(Vendor_id)
);

-- 5. APPLICATON OF COLUMN CHANGES
ALTER TABLE vendor_audits 
CHANGE COLUMN overall_risk_rating Overall_risk_complaince VARCHAR(50);


-- 6. INSERTING AUDIT DATA



-- 1. Checking total counts
SELECT 'TPRM Vendors' AS Table_Name, COUNT(*) AS Total_Rows FROM tprm_vendors
UNION ALL
SELECT 'Vendor Audits', COUNT(*) FROM Vendor_audit;

-- 2. Checking if they actually LINK
SELECT 
    COUNT(*) AS Linked_Records,
    MIN(v.vendor_name) AS Sample_Vendor,
    AVG(a.cyber_score) AS Portfolio_Avg_Cyber
FROM tprm_vendors v
JOIN Vendor_audit a ON v.vendor_id = a.vendor_id;